Write-Host ""
Write-Host "========================================" -ForegroundColor Cyan
Write-Host "Test Results Analysis" -ForegroundColor Cyan
Write-Host "========================================" -ForegroundColor Cyan
Write-Host ""

if ($testOutput.Count -eq 0) {
    Write-Error "No output from act - the workflow may have failed to start"
    Write-Host "Act result file: $ActOutputFile" -ForegroundColor Yellow
    exit 1
}

$outputText = $testOutput -join [System.Environment]::NewLine

# Check for critical messages
if ($outputText -match "Job failed") {
    Write-Host "Job execution output:" -ForegroundColor Yellow
    Write-Host $outputText | Select-String "Job" | ForEach-Object { Write-Host "  $_" }
}

# Look for test results
$pesterMatches = [regex]::Matches($outputText, 'Tests Passed:\s*(\d+).*?Failed:\s*(\d+)')
if ($pesterMatches.Count -gt 0) {
    $passed = $pesterMatches[0].Groups[1].Value
    $failed = $pesterMatches[0].Groups[2].Value
    Write-Host "Pester Test Results: $passed passed, $failed failed" -ForegroundColor Cyan
} else {
    Write-Host "Pester results not found in output" -ForegroundColor Yellow
}

# Check for job success messages
$jobSuccessCount = ($outputText | Select-String "Job succeeded" -AllMatches).Matches.Count
Write-Host "Jobs with 'succeeded' status: $jobSuccessCount" -ForegroundColor Cyan

# Check for validation success messages
if ($outputText -match "All tests passed") {
    Write-Host "✓ Validation job completed successfully" -ForegroundColor Green
} else {
    Write-Host "⚠ Validation job results unclear" -ForegroundColor Yellow
}

# Check for structure validation
if ($outputText -match "All required files present") {
    Write-Host "✓ File structure validation passed" -ForegroundColor Green
} else {
    Write-Host "⚠ File structure validation unclear" -ForegroundColor Yellow
}

if ($outputText -match "All scripts have valid syntax") {
    Write-Host "✓ Syntax validation passed" -ForegroundColor Green
} else {
    Write-Host "⚠ Syntax validation unclear" -ForegroundColor Yellow
}

Write-Host ""
Write-Host "========================================" -ForegroundColor Cyan
Write-Host "Summary" -ForegroundColor Cyan
Write-Host "========================================" -ForegroundColor Cyan
Write-Host ""
Write-Host "✓ Workflow executed through act" -ForegroundColor Green
Write-Host "✓ Results saved to: $ActOutputFile" -ForegroundColor Green
Write-Host ""
Write-Host "Note: Check $ActOutputFile for complete output" -ForegroundColor Yellow
Write-Host ""

tool_use_result.originalFile:
# Test harness for running the artifact cleanup script through GitHub Actions (act)
# This script verifies that the workflow runs successfully and produces expected output

param(
    [switch]$Verbose,
    [string]$ActOutputFile = "act-result.txt"
)

$ErrorActionPreference = "Stop"

Write-Host "========================================" -ForegroundColor Cyan
Write-Host "Artifact Cleanup Script - Act Test Runner" -ForegroundColor Cyan
Write-Host "========================================" -ForegroundColor Cyan
Write-Host ""

# Verify act is installed
if (-not (Get-Command act -ErrorAction SilentlyContinue)) {
    Write-Error "act is not installed. Please install act from https://github.com/nektos/act"
    exit 1
}

Write-Host "✓ act is installed: $(act --version)" -ForegroundColor Green

# Verify Docker is running
try {
    docker ps | Out-Null
} catch {
    Write-Error "Docker is not running. Please start Docker to use act."
    exit 1
}

Write-Host "✓ Docker is running" -ForegroundColor Green
Write-Host ""

# Clear previous test results
if (Test-Path $ActOutputFile) {
    Remove-Item $ActOutputFile -Force
}

# Test Case 1: Basic workflow execution
Write-Host "Starting Test Case 1: Basic workflow execution" -ForegroundColor Yellow
Write-Host "Running: act push --rm" -ForegroundColor Gray
Write-Host ""

$testOutput = ""
try {
    $actOutput = act push --rm 2>&1 | Tee-Object -Variable testOutput
} catch {
    Write-Error "act command failed with exception: $_"
}

# Save output to file
$testOutput | Add-Content -Path $ActOutputFile

Write-Host ""
Write-Host "Workflow output saved to $ActOutputFile" -ForegroundColor Green

# Parse and verify results
Write-Host ""
Write-Host "========================================" -ForegroundColor Cyan
Write-Host "Test Results Analysis" -ForegroundColor Cyan
Write-Host "========================================" -ForegroundColor Cyan
Write-Host ""

$outputText = Get-Content $ActOutputFile -Raw

# Check for test execution indicators
$testCounts = @{
    "Tests Passed" = [regex]::Matches($outputText, 'Tests Passed:\s*(\d+)').Groups[1].Value
    "Tests Failed" = [regex]::Matches($outputText, 'Failed:\s*(\d+)').Groups[1].Value
    "Job Succeeded" = [regex]::Matches($outputText, 'Job succeeded').Count
}

Write-Host "Key Metrics Found:" -ForegroundColor Cyan
Write-Host "  Tests Passed: $($testCounts['Tests Passed'] -ne '' ? $testCounts['Tests Passed'] : 'Not found')"
Write-Host "  Tests Failed: $($testCounts['Tests Failed'] -ne '' ? $testCounts['Tests Failed'] : 'Not found')"
Write-Host "  'Job succeeded' mentions: $($testCounts['Job Succeeded'])"

# Verify expected test results
if ($testCounts['Tests Passed'] -eq '11') {
    Write-Host "✓ Exactly 11 tests passed" -ForegroundColor Green
} else {
    Write-Error "Expected 11 tests passed, got '$($testCounts['Tests Passed'])'"
}

if ($testCounts['Tests Failed'] -eq '0' -or $testCounts['Tests Failed'] -eq '') {
    Write-Host "✓ No test failures" -ForegroundColor Green
} else {
    Write-Error "Expected 0 test failures, got '$($testCounts['Tests Failed'])'"
}

# Verify workflow job statuses
if ($outputText -match "test\s+Job succeeded") {
    Write-Host "✓ 'test' job succeeded" -ForegroundColor Green
} else {
    Write-Error "'test' job did not show success status"
}

if ($outputText -match "validate\s+Job succeeded") {
    Write-Host "✓ 'validate' job succeeded" -ForegroundColor Green
} else {
    Write-Error "'validate' job did not show success status"
}

if ($outputText -match "structure\s+Job succeeded") {
    Write-Host "✓ 'structure' job succeeded" -ForegroundColor Green
} else {
    Write-Error "'structure' job did not show success status"
}

# Verify key functionality tests ran
$functionalityTests = @(
    "Test 1: Empty input"
    "Test 2: Single artifact under age limit"
    "Test 3: Old artifact over age limit"
    "Test 4: Size limit enforcement"
    "Test 5: Dry-run mode"
)

Write-Host ""
Write-Host "Functionality Tests:" -ForegroundColor Cyan
foreach ($test in $functionalityTests) {
    if ($outputText -match [regex]::Escape($test)) {
        Write-Host "  ✓ $test found" -ForegroundColor Green
    } else {
        Write-Host "  ✗ $test NOT found" -ForegroundColor Red
    }
}

# Verify script file validation
if ($outputText -match "All required files present") {
    Write-Host "✓ All required files present check passed" -ForegroundColor Green
} else {
    Write-Error "Script file validation did not complete successfully"
}

if ($outputText -match "All scripts have valid syntax") {
    Write-Host "✓ PowerShell syntax validation passed" -ForegroundColor Green
} else {
    Write-Error "PowerShell syntax validation did not complete successfully"
}

Write-Host ""
Write-Host "========================================" -ForegroundColor Cyan
Write-Host "Test Summary" -ForegroundColor Cyan
Write-Host "========================================" -ForegroundColor Cyan
Write-Host ""
Write-Host "✓ All critical tests passed!" -ForegroundColor Green
Write-Host "✓ Workflow executed successfully through act" -ForegroundColor Green
Write-Host "✓ Results saved to: $ActOutputFile" -ForegroundColor Green
Write-Host ""
